import{_ as n,o as r,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const p="/images/uebung055.jpg",a="/images/uebung056.jpg",g=JSON.parse('{"title":"Übung Lektion 33","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung33.md","filePath":"lektionen/uebung33.md"}'),s={name:"lektionen/uebung33.md"};function l(o,e,c,u,h,m){return r(),i("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-33" tabindex="-1">Übung Lektion 33 <a class="header-anchor" href="#ubung-lektion-33" aria-label="Permalink to &quot;Übung Lektion 33&quot;">​</a></h1><p>A) Setzen Sie in folgendem Satzmuster die entsprechenden Formen der Wörter in der Klammer ein:</p><p>रामस् ... (चतुर्थ्येकवचने बहुवचने च) ... अन्नं ददाति । (भिक्षु । अग्नि । शूद्रा । गुनवान्पुत्र । देवान्स्तुवन्कवि । ब्राह्मणी । महान्साधु । धेनु)</p><p>रामो भिक्षवे ऽन्नं ददाति । रामो भिक्षुभ्यो ऽन्नं ददाति ।</p><p>रामो ऽग्नये ऽन्नं ददाति । रामो ऽग्निभ्यो ऽन्नं ददाति ।</p><p>रामः शूद्रायायन्नं ददाति । रामः शूद्राया अन्नं ददाति । रामः शूद्राभ्यो ऽन्नं ददाति ।</p><p>रामो गुणवते पुत्रायान्नं ददाति । रामो गुनवद्भ्यः पुत्रेभ्यो ऽन्नं ददाति ।</p><p>रामो देवान्स्तुवते कवये ऽन्नं ददाति । रामो देवान्स्तुवद्भ्यः कविभ्यो ऽन्नं ददाति ।</p><p>रामो ब्राह्मण्यायन्नं ददाति । रामो ब्राह्मण्या अन्नं ददाति । रामो ब्राह्मणीभ्यो ऽन्नं ददाति ।</p><p>रामो महते साधवे ऽन्नं ददाति । रामो महद्भ्यः साधुभ्यो ऽन्नं ददाति ।</p><p>रामो धेनवे ऽन्नं ददाति । रामो धेन्वायन्नं ददाति । रामो धेन्वा अन्नं ददाति । रामो धेनुभ्यो ऽन्नं ददाति ॥</p><p>B) Setzen Sie die entsprechenden Formen der in Klammern angegebenen Verben im Indikativ Präsens, Imperfekt und Optativ ein:</p><p>ब्राह्मनो घृतमग्नौ ... (हु) ॥१॥</p><p>ब्राह्मणो घृतमग्नौ जुहोति । ब्राह्मणो घृतमग्नावजुहोत् । ब्राह्मणो धृतं अग्ना अजुहोत् । ब्राह्मणो घृतमग्नौ जुहुयात् ॥१॥</p><p>बुद्धगता भयान्न ... (भी) ॥२॥</p><p>बुद्धगता भयान्न बिभ्यति । बुद्धगता भयान्नाबिभयुः । बुद्धगता भयान्न बिभीयुः ॥२॥</p><p>सुगतः कुलम् ... (हा) ॥३॥</p><p>सुगतः कुलं जहाति । सुगतः कुलमजहात् । सुगतः कुलं जह्यात् ॥३॥</p><p>दुर्जना भिक्षुभ्यो ऽन्नं न ... (दा) ॥४॥</p><p>दुर्जना भिक्षुभ्यो ऽन्नं न ददति । दुर्जना भिक्षुभ्यो ऽन्नं नाददुः । दुर्जना भिक्षुभ्यो ऽन्नं न दयुः ॥४॥</p><p>साधुः कृष्णे मतिम् ... (धा + सम् + आ) ॥५॥</p><p>साधुः कृष्णे मतिं समाधत्ते । साधुः कृष्णे मतिं समादधाति । साधुः कृष्णे मतिं समाधत्त । साधुः कृष्णे मतिं समादधात् । साधुः कृष्णे मतिं समादधीत । साधुः कृष्णे मतिं समादध्यात् ॥५॥</p><p>ईश्वरो लोकान् ... जनास्तु न ... (मा) ॥६॥</p><p>ईश्वरो लोकान्मिमीते जनास्तु न मिमते ।  ईश्वरो लोकानमिमीत जनास्तु नामिमत । ईश्वरो लोकानअमिमत जनास्तु नामिमीरन् ॥६॥</p><p>दासा भारान् ... (भृ) ॥७॥</p><p>दासा भारान्बिभर्ति । दासा भारानबिभः । दासा भारान्बिभृयात् । दासा भारान्बिभ्रति । दासा भारानबिभरुः । दासा भारान्बिभृयुः ॥७॥</p><p>ब्राह्मणी पात्रं जलेन ... (पॄ) ॥८॥</p><p>ब्राह्मणी पात्रं जलेन पिपर्ति । ब्राह्मणी पात्रं जलेनापिपः । ब्राह्मणी पात्रं जलेन पिपूर्यात् ॥८॥</p><p>C) Übersetzen Sie und wandeln Sie Singularsätze in Pluralsätze um und umgekehrt:</p><p>योगयुक्तो मतिं दुःखमक्षनयन्त्यां प्रज्ञायां समाधत्ते ॥१॥</p><p>Ein Yogin konzentriert seinen Geist auf die Einsicht, die zur Befreiung vom Leiden führt.</p><p>योगयुक्ता ... समादधते ॥१॥</p><p>यो भिक्षवे दानानि द्द्यात्सो ऽपि दानपुण्यमाददीत ॥२॥</p><p>Wer einem Mönch Gaben schenkt, der erhält das Verdienst seines Gebens.</p><p>ये ... दद्युस्ते ... आददीरन् ॥२॥</p><p>ब्राह्मणा भारं न बिभ्रतीति ब्राह्मणदासो भारं गृहमबिभः ॥३॥</p><p>Da Brahmanen keine Last tragen, trug der Diener des Brahmanen die Last nach Hause.</p><p>ब्राह्म्णो भारं न बिभर्तीति ब्राह्मणदासा भारं गृहमबिभरुः ॥३॥</p><p>क्षत्रियशूरः पुत्रमादाय योद्धुं कुलमजहात् । स युद्धे शत्रुहतत्वाच्छरीरं हीत्वा पनर्भवमैत् ॥४॥</p><p>Der Kṣatriyaheld verließ mit seinem Sohn die Familie, um zu kämpfen. Da er im Kampf vom Feind getötet wurde, verließ er seinen Körper und wurde wiedergeboren.</p><p>क्षत्रियशूराः पुत्रानादाय योद्धुं कुलान्यजहुः । ते युद्धे शत्रुहत्वाच्छरीराणि हीत्वा पुनर्भवमायन् ॥४॥</p><p>देवदत्तमपि सुखं दुःखमोक्षेष्टिं न पिपर्ति । सेष्टिः प्रज्ञयैव सम्पूर्यते ॥५॥</p><p>Selbst von den Göttern geschenktes Glück erfüllt den Wunsch nach Erlösung vom leiden nicht. Dieser Wunsch wird nur durch erlösende Einsicht voll erfüllt.</p><p>देवदत्तान्यपि सुखानि दुःखमोक्षेष्तीर्न पिपुरति । ता इष्टयः प्रज्ञयैव सम्पूर्यन्ते ॥५॥</p><p>यः साधुर्भूतेभ्यो ऽभयं ददाति तस्माद्भूतानि न बिभ्यति स च तेभ्यो न बिभेति ॥६॥</p><p>Vor einem Heiligen, der den Wesen Furchtlosigkeit schenkt, fürchten sich die Wesen nicht und er fürchtet sich nicht vor ihnen.</p><p>ये साधवो भूताय ऽभयं ददति तेभ्यो तन्न बिभेति ते च तस्मान्न बिभ्यति ॥६॥</p><p>मितमतयो नरकभयाद्स्वर्गलोभाच्च पुण्यं कुर्वन्ति पापं च जहति । अमितप्रज्ञाबुद्धा हि नरकेभ्यो न बिभीयुः स्वर्गांश्च न लुभ्येयुः । ते भयं च लोभं चारुन्धन् ॥७॥</p><p>Geistig Beschränkte tun Verdienstvolles und unterlassen Böses, weil sie sich vor Höllen fürchten und Himmel begehren. Solche, die zur unbegrenzten Einsicht erwacht sind, fürchten sich nicht vor Höllen und begehren keine Himmel. Sie haben Furcht und Begier beendet.</p><p>मितमतिर्नरकभयात्स्वर्गलोभाच्च पुण्यं करोति पापं च जहाति । अमितप्रज्ञाबुद्धो हि नरकेभ्यो न बिभीयात्स्वर्गांश्च न लुभ्येत् । स भयं च लोभं चारुणत् । ... बिभियात् ... ॥७॥</p><p><img src="'+p+'" alt=""><br> Abb.: मितमतयो नरकभयाद्स्वर्गलोभाच्च पुण्यं कुर्वन्ति पापं च जहति<br> Wat Saen Suk = วัดแสนสุข, Bang Saen = บางแสน, Thailand<br> [Bildquelle: Michael Sarver. -- <a href="http://www.flickr.com/photos/michaelsarver/72315961/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/michaelsarver/72315961/</a>. -- Zugriff am 2009-01-06. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a><a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p><img src="'+a+'" alt=""><br> Abb.: मितमतयो नरकभयाद्स्वर्गलोभाच्च पुण्यं कुर्वन्ति पापं च जहति<br> Wat Saen Suk = วัดแสนสุข, Bang Saen = บางแสน, Thailand<br> [Bildquelle: Michael Sarver. -- <a href="http://www.flickr.com/photos/michaelsarver/72315946/in/set-420804/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/michaelsarver/72315946/in/set-420804/</a>. -- Zugriff am 2009-01-06. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p>',53)])])}const b=n(s,[["render",l]]);export{g as __pageData,b as default};
